const messages = $input.all();
const webhookNode = $('Webhook Trigger');
const webhookData = webhookNode.first()?.json?.body || {};
const streamStartMs = webhookData.streamStartedAt ? new Date(webhookData.streamStartedAt).getTime() : Date.now();

// === EMPTY CHAT GUARD ===
if (messages.length === 0) {
  return [{
    json: {
      streamId: webhookData.streamId || 'no-stream-id',
      hasHighlight: false,
      startTimeOffset: 0,
      endTimeOffset: 0,
      peakCount: 0,
      totalCount: 0,
      summary: 'No chat activity recorded during the broadcast.'
    }
  }];
}

// === SLIDING WINDOW APPROACH (±15s around each message) ===
// For every message, count how many other messages fall within ±15 seconds.
// This avoids the epoch-aligned bucket-boundary splitting problem where
// a real spike straddling a 30s boundary gets artificially halved.

const timestamps = messages.map(m => new Date(m.json.serverTimestamp).getTime());
const WINDOW_HALF = 15000; // 15 seconds on each side = 30s total window

let maxCount = 0;
let peakCenterIdx = 0;

for (let i = 0; i < timestamps.length; i++) {
  const center = timestamps[i];
  let count = 0;
  for (let j = 0; j < timestamps.length; j++) {
    if (Math.abs(timestamps[j] - center) <= WINDOW_HALF) {
      count++;
    }
  }
  if (count > maxCount) {
    maxCount = count;
    peakCenterIdx = i;
  }
}

const peakCenterMs = timestamps[peakCenterIdx];
const startTimeOffset = Math.max(0, Math.floor((peakCenterMs - WINDOW_HALF - streamStartMs) / 1000));
const endTimeOffset = Math.floor((peakCenterMs + WINDOW_HALF - streamStartMs) / 1000);

return [{
  json: {
    streamId: webhookData.streamId || 'no-stream-id',
    hasHighlight: true,
    startTimeOffset,
    endTimeOffset,
    peakCount: maxCount,
    totalCount: messages.length,
    summary: `Peak chat activity: ${maxCount} messages in 30s window at ${startTimeOffset}s-${endTimeOffset}s into the stream. Total chat volume: ${messages.length} messages.`
  }
}];
